import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function SupervisorDashboard() {
  const [locations, setLocations] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [statusFilter, setStatusFilter] = useState("All");

  const [priority, setPriority] = useState("Medium");
  const [showDropdown, setShowDropdown] = useState(false);

  const [allRequests, setAllRequests] = useState([]);
  const [myRequests, setMyRequests] = useState([]);

  
  const supervisorId = localStorage.getItem("id");
  
 

  useEffect(() => {
    getLocations();
    getMyRequests();
  }, []);

  // ================= LOCATIONS =================
const getLocations = async () => {
  try {

    const res = await axios.get(
      `${Api.get_Supervisor_Locations}/${supervisorId}`
    );

    setLocations(res.data);

  } catch (err) {
    console.log(err);
  }
};

  // ================= ALL REQUESTS =================
  const getAllRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);

      const data = res.data?.data || res.data || [];
      setAllRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
      setAllRequests([]);
    }
  };

  // ================= MY REQUESTS =================
  const getMyRequests = async () => {
    try {
      const res = await axios.get(
        `${Api.get_My_Emg_Req}/${supervisorId}`
      );
      console.log(res.data);
      const data = res.data?.data || res.data || [];
      setMyRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
      setMyRequests([]);
    }
  };

  // ================= CREATE REQUEST =================
  const handleSubmit = async () => {
    try {
      if (!selectedLocation) {
        return alert("Please select location");
      }

      const res = await axios.post(Api.create_Emg_Req, {
        requestedBy: supervisorId,
        location: selectedLocation._id,
        priority,
      });

      alert(res.data.message || "Request Created Successfully");

      getAllRequests();
      getMyRequests();

      // reset UI
      setSelectedLocation(null);
      setSearch("");
      setPriority("Medium");
      setShowDropdown(false);

    } catch (err) {
      console.log(err);

      alert(
        err.response?.data?.message ||
        "This location already has an active request"
      );
    }
  };

  const steps = ["Pending", "Accepted", "Scheduled", "Arrived", "Completed"];

const filteredRequests = myRequests.filter((req) => {
  if (statusFilter === "All") {
    return req.status !== "Completed";
  }

  return req.status === statusFilter;
});


  return (

    <div className="min-h-screen bg-[#4CBB17]/20">

      {/* Header */}
      <div className="mb-8 bg-[#4CBB17]/40 px-8">
        <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
          <img
            src="garbageVehicle.jpeg"
            alt="CleanTrack Logo"
            className="w-16 h-16 object-contain"
          />

          CleanTrack
        </h1>
        <p className="text-gray-900  p-2  ">
          Smart Waste Management Control Center
        </p>
      </div>

       <div className="text-center mb-10">
        <h1 className="text-5xl font-extrabold text-black-900">
          Supervisior Dashboard
        </h1>
      </div>

      <div className="grid lg:grid-cols-3 gap-1 ">

        {/* LEFT SIDE */}
        <div className="lg:col-span-1 px-10">

          {/* Create Request */}
          <div className="bg-white rounded-2xl shadow p-6">

            <h2 className="text-3xl font-bold text-green-900 mb-6">
              Create Pickup Request
            </h2>

            {/* Location */}
            <div className="mb-5">
              <label className="font-semibold block mb-2">
                Location
              </label>

              <input
                className="w-full border rounded-xl p-3"
                placeholder="Search pickup address..."
                value={search}
                onChange={(e) => {
                  setSearch(e.target.value);
                  setShowDropdown(true);
                }}
  //                 onFocus={() => setShowDropdown(true)}
  // onBlur={() => {
  //   setTimeout(() => {
  //     setShowDropdown(false);
  //   }, 200);
  // }}
              />

              {showDropdown && (
                <div className="border rounded-xl mt-2 max-h-40 overflow-y-auto">
                  {locations
.filter((l) =>
  l.locationName
    ?.toLowerCase()
    .includes(search.toLowerCase())
  )
                    .map((loc) => (
                      <div
                        key={loc._id}
                        onClick={() => {
                          setSelectedLocation(loc);
                          setSearch(loc.locationName);
                          setShowDropdown(false);
                        }}
                        className="p-3 hover:bg-gray-100 cursor-pointer"
                      >
                       {loc.locationName}
                      </div>
                    ))}
                </div>
              )}
            </div>

            {/* Priority */}
            <div className="mb-6">
              <label className="font-semibold block mb-3">
                Priority Level
              </label>

              <div className="flex gap-3">
                {["Low", "Medium", "High"].map((p) => (
                  <button
                    key={p}
                    onClick={() => setPriority(p)}
                    className={`flex-1 py-3 rounded-full font-semibold ${priority === p
                        ? "bg-green-800 text-white"
                        : "border"
                      }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>

            <button
              onClick={handleSubmit}
              className="w-full bg-green-800 text-white py-4 rounded-xl text-lg font-bold"
            >
              Create Request
            </button>
          </div>
        </div>

        {/* RIGHT SIDE */}
        <div className="lg:col-span-2 px-12">

<div className="bg-white rounded-2xl shadow p-6">
 <div className="flex justify-between items-center mb-6">

  <div>
    <h2 className="text-3xl font-bold">
      Active Requests
    </h2>

    <p className="text-gray-500 text-sm">
       Pickup Scheduling & Monitoring
    </p>
  </div>

  <select
    value={statusFilter}
    onChange={(e) =>
      setStatusFilter(e.target.value)
    }
    className="border border-gray-300 rounded-xl px-4 py-2 bg-white shadow-sm"
  >
    <option value="All">
      All Active
    </option>

    <option value="Pending">
      Pending
    </option>

    <option value="Scheduled">
      Scheduled
    </option>

    <option value="Arrived">
      Arrived
    </option>

    <option value="Completed">
      Completed
    </option>
  </select>

</div>

  {filteredRequests.length === 0 ? (
    <div className="flex flex-col items-center justify-center py-16">
      <div className="text-6xl mb-4">🧹</div>

      <h3 className="text-2xl font-bold text-gray-500">
        No Requests Found
      </h3>

     
    </div>
  ) : (
    <div className="grid md:grid-cols-2 gap-4">
      {filteredRequests.map((req) => (
        <div
          key={req._id}
          className="border rounded-2xl p-5 hover:shadow-lg transition"
        >
          <p className="text-xs text-gray-500">
            REQUEST #{req._id.slice(-4)}
          </p>

          <h3 className="text-xl font-semibold text-green-800">
           📍{req.location?.locationName}
          </h3>

          <div className="flex justify-between mt-4">
            <span>
              Priority: {req.priority}
            </span>

            <span
              className={
                req.status === "Completed"
                  ? "bg-green-500 text-white px-4 py-1 rounded-full"
                  : req.status === "Scheduled"
                  ? "bg-sky-500 text-white px-4 py-1 rounded-full"
                  : req.status === "Pending"
                  ? "bg-yellow-500 text-black px-4 py-1 rounded-full"
                  : req.status === "Arrived"
                  ? "bg-orange-500 text-white px-4 py-1 rounded-full"
                  : "bg-gray-500 text-white px-4 py-1 rounded-full"
              }
            >
              {req.status}
            </span>
          </div>

          <p className="text-sm text-gray-500 mt-4">
            Created:{" "}
            {new Date(req.createdAt).toLocaleString("en-IN", {
              day: "2-digit",
              month: "short",
              year: "numeric",
              hour: "2-digit",
              minute: "2-digit",
              hour12: true,
            })}
          </p>

          {req.scheduledDate && (
  <p className="text-sm text-sky-700 mt-2 font-medium">
     Scheduled:
    {" "}
    {new Date(req.scheduledDate).toLocaleDateString("en-IN", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    })}
    {" | "}
    {req.scheduledTime}
  </p>
)}

{req.arrivedAt && (
  <p className="text-sm text-yellow-700 mt-2 font-medium">
    Arrived:
    {" "}
    {new Date(req.arrivedAt).toLocaleString("en-IN", {
      day: "2-digit",
      month: "short",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      hour12: true,
    })}
  </p>
)}

{req.completedAt && (
  <p className="text-sm text-green-700 mt-2 font-medium">
     Completed:
    {" "}
    {new Date(req.completedAt).toLocaleString("en-IN", {
      day: "2-digit",
      month: "short",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      hour12: true,
    })}
  </p>
)}
        </div>
      ))}
    </div>
  )}
</div>
        </div>

      </div>
    </div>);
}
